import requests

def test_post_generate_skill_short_creator_content_validation_error():
    base_url = "http://localhost:8001"
    url = f"{base_url}/api/generate-skill"
    payload = {
        "creator_content": "short"
    }
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=5)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"
    assert response.status_code == 422, f"Expected status code 422, got {response.status_code}"
    try:
        json_resp = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"
    # Validate Pydantic v2 style validation error for string_too_short on creator_content
    # Structure expected (example):
    # {
    #   "detail": [
    #       {
    #           "type": "string_too_short",
    #           "loc": ["body", "creator_content"],
    #           "msg": "ensure this value has at least 40 characters",
    #           "input": "short",
    #           "ctx": {"min_length": 40}
    #       }
    #   ]
    # }
    assert "detail" in json_resp, "Response JSON missing 'detail' field"
    details = json_resp["detail"]
    assert isinstance(details, list) and len(details) > 0, "'detail' is not a non-empty list"
    found_error = False
    for error in details:
        if (
            isinstance(error, dict)
            and error.get("type") == "string_too_short"
            and error.get("loc") == ["body", "creator_content"]
        ):
            found_error = True
            break
    assert found_error, "Expected validation error for 'creator_content' with type 'string_too_short' and loc ['body', 'creator_content'] not found"

test_post_generate_skill_short_creator_content_validation_error()

import requests

def test_post_generate_skill_twitter_missing_bearer_token():
    url = "http://localhost:8001/api/generate-skill/twitter"
    payload = {"twitter_username": "testuser"}
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=5)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 400, f"Expected status code 400, got {response.status_code}"
    try:
        json_response = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"
    assert isinstance(json_response, dict), "Response JSON is not a dictionary"
    assert "message" in json_response, "Response JSON missing 'message' key"
    assert json_response["message"] == "X_BEARER_TOKEN not configured", f"Unexpected message: {json_response.get('message')}"

test_post_generate_skill_twitter_missing_bearer_token()

import requests
import time

BASE_URL = "http://localhost:8001"
TIMEOUT_SECONDS = 5

def test_post_generate_skill_twitter_user_not_found():
    url = f"{BASE_URL}/api/generate-skill/twitter"
    # Use a non-existent twitter_username under 15 chars to meet validation but simulate not found
    payload = {
        "twitter_username": "zzznotreal99"
    }
    headers = {
        "Content-Type": "application/json"
    }
    start_time = time.time()
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT_SECONDS)
    except requests.exceptions.Timeout:
        assert False, "Request timed out, must complete under 5 seconds"
    elapsed = time.time() - start_time
    assert elapsed < TIMEOUT_SECONDS, f"Test exceeded time limit of {TIMEOUT_SECONDS} seconds"
    # The expected response status code is 502 indicating upstream X API error for user not found
    assert response.status_code == 502, f"Expected status code 502 but got {response.status_code}"
    # Response JSON body should contain detail with indication of not found error
    try:
        body = response.json()
    except Exception:
        assert False, "Response is not valid JSON"

    detail = body.get("detail", "") or body.get("message", "")
    assert isinstance(detail, str) and "not found" in detail.lower(), "Expected error detail to contain 'not found'"

test_post_generate_skill_twitter_user_not_found()
